import{_ as a,o,c as i,ag as r}from"./chunks/framework.DTiDeF2Q.js";const u=JSON.parse('{"title":"Caminhos (Paths) | Dotfiles (PT)","titleTemplate":":title","description":"Como o Dotfiles gerencia sua hierarquia \\\\$PATH para garantir que as ferramentas certas sejam carregadas na ordem certa.","frontmatter":{"title":"Caminhos (Paths) | Dotfiles","description":"Como o Dotfiles gerencia sua hierarquia \\\\$PATH para garantir que as ferramentas certas sejam carregadas na ordem certa.","lang":"pt-BR","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Caminhos (Paths) preview","canonical":"/pt/paths/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Caminhos (Paths)","pageType":"docs","schemaType":"WebPage","metaTitle":"Caminhos (Paths) - Dotfiles (BR)","permalink":"/pt/paths/","meta":[{"name":"keywords","content":"caminho, ambiente, variáveis, hierarquia, dotfiles, chezmoi"}]},"headers":[],"relativePath":"pt/paths/index.md","filePath":"pt/paths/index.md","lastUpdated":1773010926000}'),t={name:"pt/paths/index.md"};function s(n,e,d,l,c,m){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="gerenciamento-de-caminhos-path" tabindex="-1">Gerenciamento de Caminhos (Path) <a class="header-anchor" href="#gerenciamento-de-caminhos-path" aria-label="Permalink to &quot;Gerenciamento de Caminhos (Path)&quot;">​</a></h1><p>Uma das funções mais críticas do Dotfiles é gerenciar sua variável de ambiente <code>$PATH</code>. Isso determina qual versão de uma ferramenta é executada quando você digita um comando.</p><p>Aderimos a uma hierarquia estrita para garantir consistência entre macOS e Linux.</p><h2 id="a-hierarquia" tabindex="-1">A Hierarquia <a class="header-anchor" href="#a-hierarquia" aria-label="Permalink to &quot;A Hierarquia&quot;">​</a></h2><p>Da prioridade mais alta (verificada primeiro) para a mais baixa:</p><ol><li><p><strong>Binários Locais</strong> (<code>~/.local/bin</code>)</p><ul><li><strong>Prioridade</strong>: 1</li><li><strong>Objetivo</strong>: Scripts de usuário personalizados, CLI <code>dot</code> e ferramentas instaladas via <code>pipx</code> ou outros gerenciadores de pacotes de nível de usuário.</li><li><strong>Motivo</strong>: Permite substituir ferramentas do sistema ou Homebrew por suas próprias versões.</li></ul></li><li><p><strong>Binários de Aplicativos</strong> (macOS)</p><ul><li><strong>Prioridade</strong>: 2</li><li><strong>Objetivo</strong>: Binários de aplicativos instalados (por exemplo, VS Code, iTerm).</li></ul></li><li><p><strong>Runtimes de Linguagem</strong></p><ul><li><strong>Node.js</strong>: <code>~/.node_modules/bin</code></li><li><strong>Go</strong>: <code>~/go/bin</code></li><li><strong>Rust (Cargo)</strong>: <code>~/.cargo/bin</code></li><li><strong>Ruby (User Gems)</strong>: <code>~/.gem/ruby/bin</code></li><li><strong>Python (Pipx)</strong>: <code>~/.local/share/pipx</code></li></ul></li><li><p><strong>Homebrew</strong> (<code>/opt/homebrew/bin</code>)</p><ul><li><strong>Prioridade</strong>: 3</li><li><strong>Objetivo</strong>: Gerenciador de pacotes principal para macOS/Linux.</li><li><strong>Nota</strong>: Carregamos o Homebrew propositalmente <em>antes</em> dos caminhos do sistema para permitir a atualização de ferramentas do sistema (como <code>git</code> or <code>curl</code>).</li></ul></li><li><p><strong>Caminhos do Sistema</strong> (<code>/usr/bin</code>, <code>/bin</code>)</p><ul><li><strong>Prioridade</strong>: Mais baixa</li><li><strong>Objetivo</strong>: Ferramentas padrão do sistema operacional.</li><li><strong>Motivo</strong>: Fallback para utilitários fundamentais.</li></ul></li></ol><h2 id="deduplicacao" tabindex="-1">Deduplicação <a class="header-anchor" href="#deduplicacao" aria-label="Permalink to &quot;Deduplicação&quot;">​</a></h2><p>O Dotfiles deduplica automaticamente seu <code>$PATH</code> enquanto preserva a ordem de precedência. Isso evita que a variável <code>$PATH</code> cresça indefinidamente ao gerar shells aninhados.</p>',8)])])}const g=a(t,[["render",s]]);export{u as __pageData,g as default};
